<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\WorldMaps\WorldMapAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\WorldMapAreaRequest;use App\Models\WorldMap;use App\Models\WorldMapArea;
final class WorldMapAreaController extends Controller{public function store(WorldMapAreaRequest $request,WorldMap $worldMap,WorldMapAdminService $service){return$this->save($request,$worldMap,null,$service,'Área creada correctamente.');}public function update(WorldMapAreaRequest $request,WorldMap $worldMap,WorldMapArea $worldMapArea,WorldMapAdminService $service){$this->scope($worldMap,$worldMapArea);return$this->save($request,$worldMap,$worldMapArea,$service,'Área actualizada correctamente.');}public function activate(WorldMap $worldMap,WorldMapArea $worldMapArea,WorldMapAdminService $service){$this->scope($worldMap,$worldMapArea);return$this->status(function()use($service,$worldMap,$worldMapArea){$service->activateArea($worldMap,$worldMapArea,request('version'));},'Área activada correctamente.');}public function deactivate(WorldMap $worldMap,WorldMapArea $worldMapArea,WorldMapAdminService $service){$this->scope($worldMap,$worldMapArea);return$this->status(function()use($service,$worldMap,$worldMapArea){$service->deactivateArea($worldMap,$worldMapArea,request('version'));},'Área desactivada correctamente.');}public function destroy(WorldMap $worldMap,WorldMapArea $worldMapArea,WorldMapAdminService $service){return$this->deactivate($worldMap,$worldMapArea,$service);}private function save($request,$map,$area,$service,$message){try{$service->saveArea($map,$request->validated(),$area);return redirect()->route('admin.content.world-maps.editor',$map)->with('status',$message);}catch(\Throwable $e){return back()->withInput()->withErrors(['world_map_area'=>$e->getMessage()]);}}private function status($callback,$message){try{$callback();return back()->with('status',$message);}catch(\Throwable $e){return back()->withErrors(['world_map_area'=>$e->getMessage()]);}}private function scope($map,$area){if((int)$area->world_map_id!==(int)$map->id)abort(404);}}
